    bool mNow = pirm.isMotionDetected(); bool wave   = mNow && !pMot;   pMot = mNow;
    long pos = knob.getPosition();
    long dPos = pos - lastPos; lastPos = pos;

    char buf[40];
    auto center = [&](const char* s, int y, int sz, uint16_t c){
      screen.setCursor((int)((160 - (int)strlen(s) * 6 * sz) / 2), y);
      screen.setTextSize(sz); screen.setTextColor(c); screen.print(s);
    };
    auto emitState = [&](const char* key, long v){
      Serial.print("{\"type\":\"event\",\"payload\":{\"event_type\":\"state\",\"key\":\"");
      Serial.print(key);
      Serial.print("\",\"value\":");
      Serial.print(v);
      Serial.println(",\"source\":\"game\"}}");
    };
    auto feedback = [&](int pts){
      if (pts >= 90)      { led.setAll(0, 255, 0);   spk.playNote(NOTE_C5, 90); spk.playNote(NOTE_E5, 90); spk.playNote(NOTE_G5, 150); }
      else if (pts >= 50) { led.setAll(255, 140, 0); spk.playNote(NOTE_E4, 120); spk.playNote(NOTE_G4, 150); }
      else                { led.setAll(255, 0, 0);   spk.playTone(150, 350); }
      led.show(); ledOff = millis() + 1200;
    };
    uint16_t ptsColor = lastPts >= 90 ? ST7735_TFT::COLOR_GREEN
                      : (lastPts >= 50 ? ST7735_TFT::COLOR_ORANGE : ST7735_TFT::COLOR_RED);

    if (ledOff && millis() > ledOff) { led.clear(); led.show(); ledOff = 0; }

