        center(buf, 4, 1, ST7735_TFT::COLOR_CYAN);
        snprintf(buf, sizeof buf, "%ld.%ld s", g2t[rnd] / 1000, (g2t[rnd] % 1000) / 100);
        center(buf, 18, 3, ST7735_TFT::COLOR_YELLOW);
        center("count in the dark, wave!", 48, 1, ST7735_TFT::COLOR_WHITE);
        if (!pirm.isWarmedUp()) center("sensor warming up...", 66, 1, ST7735_TFT::COLOR_RED);
